  }
}, null, 2));

// Create directory structure
await daytona.exec("mkdir -p /workspace/src /workspace/public /workspace/tests");

// Create database module
const dbCode = `import Database from "bun:sqlite";
import { randomBytes } from "crypto";

const db = new Database("/workspace/links.db");

db.exec(\`
  CREATE TABLE IF NOT EXISTS links (
    id TEXT PRIMARY KEY,
    url TEXT NOT NULL,
    clicks INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )
\`);

export function createShortUrl(url: string): string {
  // Generate a 6-char random ID
  const id = randomBytes(4).toString("hex").slice(0, 6);
  const stmt = db.prepare("INSERT INTO links (id, url) VALUES (?, ?)");
  try {
    stmt.run(id, url);
    return id;
  } catch (e: any) {
    if (e.message.includes("UNIQUE constraint failed")) {
      // Retry on collision
      return createShortUrl(url);
    }
    throw e;
  }
}

export function getUrl(id: string): { url: string; clicks: number } | null {
  const row = db.query("SELECT url, clicks FROM links WHERE id = ?").get(id) as any;
  return row || null;
}

export function incrementClicks(id: string): void {
  db.prepare("UPDATE links SET clicks = clicks + 1 WHERE id = ?").run(id);
}

export function getAllLinks(): Array<{ id: string; url: string; clicks: number; created_at: string }> {
  return db.query("SELECT id, url, clicks, created_at FROM links ORDER BY created_at DESC").all() as any;
}

export function deleteLink(id: string): boolean {
  const result = db.prepare("DELETE FROM links WHERE id = ?").run(id);
  return result.changes > 0;
}
`;

await daytona.write("/workspace/src/db.ts", dbCode);

// Create server
const serverCode = `import express from "express";
import { createShortUrl, getUrl, incrementClicks, getAllLinks } from "./db";
import path from "path";

const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.json());
app.use(express.static(path.join(__dirname, "../public")));

// Health check
app.get("/api/health", (_req, res) => {
  res.json({ status: "ok" });
});

// Create short URL
app.post("/api/shorten", (req, res) => {
  const { url } = req.body;
  if (!url || typeof url !== "string") {
    res.status(400).json({ error: "URL is required" });
    return;
  }

  try {
    new URL(url);
  } catch {
    res.status(400).json({ error: "Invalid URL" });
    return;
  }

  const id = createShortUrl(url);
  const shortUrl = \`\${req.protocol}://\${req.get("host")}/\${id}\`;
  res.json({ id, shortUrl, url });
});

// Get all links (dashboard data)
app.get("/api/links", (_req, res) => {
  const links = getAllLinks();
  res.json(links);
});

// Redirect short URL
app.get("/:id", (req, res) => {
  const { id } = req.params;
  const link = getUrl(id);
  if (!link) {
    res.status(404).send("Link not found");
    return;
  }
  incrementClicks(id);
  res.redirect(link.url);
});

app.listen(PORT, () => {
  console.log(\`Server running on http://localhost:\${PORT}\`);
});

export default app;
`;

