    const links = await res.json();
    renderLinks(links);
  } catch (err) {
    console.error('Failed to load links:', err);
  }
}

function renderLinks(links) {
  if (links.length === 0) {
    linksTbody.innerHTML = \`<tr class="empty-row"><td colspan="4">No links created yet</td></tr>\`;
    return;
